),
resolved AS (
    SELECT
        inst.id AS instrument_id,
        s.trade_date,
        s.price::numeric(18,4) AS price,
        inst.currency_id,
        md5(inst.id::text || '|' || s.trade_date::text || '|TBANK') AS hash_key
    FROM src s
    JOIN LATERAL (
        SELECT i.id, i.currency_id
        FROM instruments i
        LEFT JOIN instrument_aliases ia ON ia.instrument_id = i.id
        WHERE upper(coalesce(i.figi, '')) = upper(s.db_code)
           OR upper(i.ticker) = upper(s.db_code)
           OR upper(coalesce(i.isin, '')) = upper(s.db_code)
           OR upper(coalesce(ia.normalized_alias_code, '')) = upper(s.db_code)
        ORDER BY
            CASE
                WHEN upper(coalesce(i.figi, '')) = upper(s.db_code) THEN 1
                WHEN upper(i.ticker) = upper(s.db_code) THEN 2
                WHEN upper(coalesce(i.isin, '')) = upper(s.db_code) THEN 3
                ELSE 4
            END,
            i.created_at
        LIMIT 1
    ) inst ON true
)
INSERT INTO prices (id, instrument_id, date, value, currency_id, provider, created_at, updated_at)
SELECT
    (
        substr(hash_key, 1, 8) || '-' ||
        substr(hash_key, 9, 4) || '-' ||
        substr(hash_key, 13, 4) || '-' ||
        substr(hash_key, 17, 4) || '-' ||
        substr(hash_key, 21, 12)
    )::uuid,
    instrument_id,
    (trade_date::timestamp AT TIME ZONE 'UTC'),
    price,
    currency_id,
    'TBANK',
    now(),
    now()
FROM resolved
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    updated_at = now();

COMMIT;
-- ===== END scripts/tbank_history/sql/prices_2022.sql =====


DO $$
DECLARE
    expected_moex bigint := 38452;
    expected_tbank bigint := 1639;
    actual_moex bigint;
    actual_tbank bigint;
    actual_total bigint;
BEGIN
    WITH scoped AS (
        SELECT provider, count(*) AS rows_count
        FROM prices
        WHERE date >= TIMESTAMP '2022-01-01 00:00:00+00'
          AND date < TIMESTAMP '2023-01-01 00:00:00+00'
          AND upper(provider) IN ('MOEX', 'TBANK')
        GROUP BY provider
    )
    SELECT
        COALESCE(max(CASE WHEN upper(provider) = 'MOEX' THEN rows_count END), 0),
        COALESCE(max(CASE WHEN upper(provider) = 'TBANK' THEN rows_count END), 0),
        COALESCE(sum(rows_count), 0)
    INTO actual_moex, actual_tbank, actual_total
    FROM scoped;

    IF actual_moex <> expected_moex THEN
        RAISE EXCEPTION 'Consolidated 2022 validation failed: expected MOEX %, got %.', expected_moex, actual_moex;
    END IF;

    IF actual_tbank <> expected_tbank THEN
        RAISE EXCEPTION 'Consolidated 2022 validation failed: expected TBANK %, got %.', expected_tbank, actual_tbank;
    END IF;

    IF actual_total <> expected_moex + expected_tbank THEN
        RAISE EXCEPTION 'Consolidated 2022 validation failed: expected total %, got %.', expected_moex + expected_tbank, actual_total;
    END IF;

    RAISE NOTICE 'Consolidated 2022 validation passed. MOEX: %, TBANK: %, total: %.', actual_moex, actual_tbank, actual_total;
END $$;
